import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function Checkout({ token }) {
  const [cart, setCart] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetchCart();
  }, []);

  const fetchCart = async () => {
    try {
      const res = await axios.get('/api/cart', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCart(res.data);
    } catch (err) {
      setError('Failed to load cart');
    } finally {
      setLoading(false);
    }
  };

  const handleCheckout = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/orders/checkout', {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setSuccess(res.data.message);
      setTimeout(() => {
        navigate('/orders');
      }, 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'Checkout failed');
    }
  };

  if (loading) return <div className="loading">Loading...</div>;

  const total = cart?.items.reduce((sum, item) => sum + (item.productId?.price || 0) * item.quantity, 0) || 0;

  return (
    <div>
      <h1>Checkout</h1>
      {error && <div className="error-message">{error}</div>}
      {success && <div className="success-message">{success}</div>}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '30px', marginTop: '30px' }}>
        {/* Order Summary */}
        <div>
          <h2>Order Summary</h2>
          <table className="cart-table">
            <thead>
              <tr>
                <th>Product</th>
                <th>Qty</th>
                <th>Price</th>
              </tr>
            </thead>
            <tbody>
              {cart?.items.map(item => (
                <tr key={item.productId?._id}>
                  <td>{item.productId?.name}</td>
                  <td>{item.quantity}</td>
                  <td>฿{(item.productId?.price || 0) * item.quantity}</td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="checkout-summary">
            <div className="summary-item">
              <span>Subtotal:</span>
              <span>฿{total}</span>
            </div>
            <div className="summary-item">
              <span>Shipping:</span>
              <span>฿0</span>
            </div>
            <div className="summary-item">
              <span>Tax:</span>
              <span>฿0</span>
            </div>
            <div className="summary-item total">
              <span>Total:</span>
              <span>฿{total}</span>
            </div>
          </div>
        </div>

        {/* Checkout Form */}
        <form onSubmit={handleCheckout} style={{ background: 'white', padding: '20px', borderRadius: '8px', height: 'fit-content' }}>
          <h2>Shipping Address</h2>

          <div className="form-group">
            <label>Full Name *</label>
            <input type="text" required />
          </div>

          <div className="form-group">
            <label>Email *</label>
            <input type="email" required />
          </div>

          <div className="form-group">
            <label>Phone *</label>
            <input type="tel" required />
          </div>

          <div className="form-group">
            <label>Address *</label>
            <textarea required rows="4"></textarea>
          </div>

          <div className="form-group">
            <label>City *</label>
            <input type="text" required />
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
            <div className="form-group">
              <label>Province *</label>
              <input type="text" required />
            </div>
            <div className="form-group">
              <label>Postal Code *</label>
              <input type="text" required />
            </div>
          </div>

          <button type="submit" style={{ width: '100%', marginTop: '20px', fontSize: '16px', padding: '12px' }}>
            Complete Order
          </button>
        </form>
      </div>
    </div>
  );
}

export default Checkout;
